1	// Package model contains types and utilities for parsing, validating, and
2	// working with model names and digests.
3	package model
4	
5	import (
6		"cmp"
7		"errors"
8		"fmt"
9		"log/slog"
10		"net/url"
11		"path/filepath"
12		"strings"
13	)
14	
15	// Errors
16	var (
17		// ErrUnqualifiedName represents an error where a name is not fully
18		// qualified. It is not used directly in this package, but is here
19		// to avoid other packages inventing their own error type.
20		// Additionally, it can be conveniently used via [Unqualified].
21		ErrUnqualifiedName = errors.New("unqualified name")
22	)
23	
24	// Unqualified is a helper function that returns an error with
25	// ErrUnqualifiedName as the cause and the name as the message.
26	func Unqualified(n Name) error {
27		return fmt.Errorf("%w: %s", ErrUnqualifiedName, n)
28	}
29	
30	// MissingPart is used to indicate any part of a name that was "promised" by
31	// the presence of a separator, but is missing.
32	//
33	// The value was chosen because it is deemed unlikely to be set by a user,
34	// not a valid part name valid when checked by [Name.IsValid], and easy to
35	// spot in logs.
36	const MissingPart = "!MISSING!"
37	
38	const (
39		defaultHost           = "registry.ollama.ai"
40		defaultNamespace      = "library"
41		defaultTag            = "latest"
42		defaultProtocolScheme = "https"
43	)
44	
45	// DefaultName returns a name with the default values for the host, namespace,
46	// tag, and protocol scheme parts. The model and digest parts are empty.
47	//
48	//   - The default host is ("registry.ollama.ai")
49	//   - The default namespace is ("library")
50	//   - The default tag is ("latest")
51	//   - The default protocol scheme is ("https")
52	func DefaultName() Name {
53		return Name{
54			Host:           defaultHost,
55			Namespace:      defaultNamespace,
56			Tag:            defaultTag,
57			ProtocolScheme: defaultProtocolScheme,
58		}
59	}
60	
61	type partKind int
62	
63	const (
64		kindHost partKind = iota
65		kindNamespace
66		kindModel
67		kindTag
68		kindDigest
69	)
70	
71	func (k partKind) String() string {
72		switch k {
73		case kindHost:
74			return "host"
75		case kindNamespace:
76			return "namespace"
77		case kindModel:
78			return "model"
79		case kindTag:
80			return "tag"
81		case kindDigest:
82			return "digest"
83		default:
84			return "unknown"
85		}
86	}
87	
88	// Name is a structured representation of a model name string, as defined by
89	// [ParseNameNoDefaults].
90	//
91	// It is not guaranteed to be valid. Use [Name.IsValid] to check if the name
92	// is valid.
93	type Name struct {
94		Host           string
95		Namespace      string
96		Model          string
97		Tag            string
98		ProtocolScheme string
99	}
100	
101	// ParseName parses and assembles a Name from a name string. The
102	// format of a valid name string is:
103	//
104	//	  s:
105	//		  { host } "/" { namespace } "/" { model } ":" { tag } "@" { digest }
106	//		  { host } "/" { namespace } "/" { model } ":" { tag }
107	//		  { host } "/" { namespace } "/" { model } "@" { digest }
108	//		  { host } "/" { namespace } "/" { model }
109	//		  { namespace } "/" { model } ":" { tag } "@" { digest }
110	//		  { namespace } "/" { model } ":" { tag }
111	//		  { namespace } "/" { model } "@" { digest }
112	//		  { namespace } "/" { model }
113	//		  { model } ":" { tag } "@" { digest }
114	//		  { model } ":" { tag }
115	//		  { model } "@" { digest }
116	//		  { model }
117	//		  "@" { digest }
118	//	  host:
119	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." | ":" }*
120	//	      length:  [1, 350]
121	//	  namespace:
122	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" }*
123	//	      length:  [1, 80]
124	//	  model:
125	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." }*
126	//	      length:  [1, 80]
127	//	  tag:
128	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." }*
129	//	      length:  [1, 80]
130	//	  digest:
131	//	      pattern: { alphanum | "_" } { alphanum | "-" | ":" }*
132	//	      length:  [1, 80]
133	//
134	// Most users should use [ParseName] instead, unless need to support
135	// different defaults than DefaultName.
136	//
137	// The name returned is not guaranteed to be valid. If it is not valid, the
138	// field values are left in an undefined state. Use [Name.IsValid] to check
139	// if the name is valid.
140	func ParseName(s string) Name {
141		return Merge(ParseNameBare(s), DefaultName())
142	}
143	
144	// ParseNameBare parses s as a name string and returns a Name. No merge with
145	// [DefaultName] is performed.
146	func ParseNameBare(s string) Name {
147		var n Name
148		var promised bool
149	
150		// "/" is an illegal tag character, so we can use it to split the host
151		if strings.LastIndex(s, ":") > strings.LastIndex(s, "/") {
152			s, n.Tag, _ = cutPromised(s, ":")
153		}
154	
155		s, n.Model, promised = cutPromised(s, "/")
156		if !promised {
157			n.Model = s
158			return n
159		}
160	
161		s, n.Namespace, promised = cutPromised(s, "/")
162		if !promised {
163			n.Namespace = s
164			return n
165		}
166	
167		scheme, host, ok := strings.Cut(s, "://")
168		if ok {
169			n.ProtocolScheme = scheme
170		} else {
171			host = scheme
172		}
173		n.Host = host
174	
175		return n
176	}
177	
178	// ParseNameFromFilepath parses a 4-part filepath as a Name. The parts are
179	// expected to be in the form:
180	//
181	// { host } "/" { namespace } "/" { model } "/" { tag }
182	func ParseNameFromFilepath(s string) (n Name) {
183		parts := strings.Split(s, string(filepath.Separator))
184		if len(parts) != 4 {
185			return Name{}
186		}
187	
188		n.Host = parts[0]
189		n.Namespace = parts[1]
190		n.Model = parts[2]
191		n.Tag = parts[3]
192		if !n.IsFullyQualified() {
193			return Name{}
194		}
195	
196		return n
197	}
198	
199	// Merge merges the host, namespace, tag, and protocol scheme parts of the two names,
200	// preferring the non-empty parts of a.
201	func Merge(a, b Name) Name {
202		a.Host = cmp.Or(a.Host, b.Host)
203		a.Namespace = cmp.Or(a.Namespace, b.Namespace)
204		a.Tag = cmp.Or(a.Tag, b.Tag)
205		a.ProtocolScheme = cmp.Or(a.ProtocolScheme, b.ProtocolScheme)
206		return a
207	}
208	
209	// String returns the name string, in the format that [ParseNameNoDefaults]
210	// accepts as valid, if [Name.IsValid] reports true; otherwise the empty
211	// string is returned.
212	func (n Name) String() string {
213		var b strings.Builder
214		if n.Host != "" {
215			b.WriteString(n.Host)
216			b.WriteByte('/')
217		}
218		if n.Namespace != "" {
219			b.WriteString(n.Namespace)
220			b.WriteByte('/')
221		}
222		b.WriteString(n.Model)
223		if n.Tag != "" {
224			b.WriteByte(':')
225			b.WriteString(n.Tag)
226		}
227		return b.String()
228	}
229	
230	// DisplayShortest returns a short string version of the name.
231	func (n Name) DisplayShortest() string {
232		var sb strings.Builder
233	
234		if !strings.EqualFold(n.Host, defaultHost) {
235			sb.WriteString(n.Host)
236			sb.WriteByte('/')
237			sb.WriteString(n.Namespace)
238			sb.WriteByte('/')
239		} else if !strings.EqualFold(n.Namespace, defaultNamespace) {
240			sb.WriteString(n.Namespace)
241			sb.WriteByte('/')
242		}
243	
244		// always include model and tag
245		sb.WriteString(n.Model)
246		sb.WriteString(":")
247		sb.WriteString(n.Tag)
248		return sb.String()
249	}
250	
251	// IsValidNamespace reports whether the provided string is a valid
252	// namespace.
253	func IsValidNamespace(s string) bool {
254		return isValidPart(kindNamespace, s)
255	}
256	
257	// IsValid reports whether all parts of the name are present and valid. The
258	// digest is a special case, and is checked for validity only if present.
259	//
260	// Note: The digest check has been removed as is planned to be added back in
261	// at a later time.
262	func (n Name) IsValid() bool {
263		return n.IsFullyQualified()
264	}
265	
266	// IsFullyQualified returns true if all parts of the name are present and
267	// valid without the digest.
268	func (n Name) IsFullyQualified() bool {
269		parts := []string{
270			n.Host,
271			n.Namespace,
272			n.Model,
273			n.Tag,
274		}
275		for i, part := range parts {
276			if !isValidPart(partKind(i), part) {
277				return false
278			}
279		}
280		return true
281	}
282	
283	// Filepath returns a canonical filepath that represents the name with each part from
284	// host to tag as a directory in the form:
285	//
286	//	{host}/{namespace}/{model}/{tag}
287	//
288	// It uses the system's filepath separator and ensures the path is clean.
289	//
290	// It panics if the name is not fully qualified. Use [Name.IsFullyQualified]
291	// to check if the name is fully qualified.
292	func (n Name) Filepath() string {
293		if !n.IsFullyQualified() {
294			panic("illegal attempt to get filepath of invalid name")
295		}
296		return filepath.Join(
297			n.Host,
298			n.Namespace,
299			n.Model,
300			n.Tag,
301		)
302	}
303	
304	// LogValue returns a slog.Value that represents the name as a string.
305	func (n Name) LogValue() slog.Value {
306		return slog.StringValue(n.String())
307	}
308	
309	func (n Name) EqualFold(o Name) bool {
310		return strings.EqualFold(n.Host, o.Host) &&
311			strings.EqualFold(n.Namespace, o.Namespace) &&
312			strings.EqualFold(n.Model, o.Model) &&
313			strings.EqualFold(n.Tag, o.Tag)
314	}
315	
316	// BaseURL returns the base URL for the registry.
317	func (n Name) BaseURL() *url.URL {
318		return &url.URL{
319			Scheme: n.ProtocolScheme,
320			Host:   n.Host,
321		}
322	}
323	
324	// DisplayNamespaceModel returns the namespace and model joined by "/".
325	func (n Name) DisplayNamespaceModel() string {
326		var b strings.Builder
327		b.WriteString(n.Namespace)
328		b.WriteByte('/')
329		b.WriteString(n.Model)
330		return b.String()
331	}
332	
333	func isValidLen(kind partKind, s string) bool {
334		switch kind {
335		case kindHost:
336			return len(s) >= 1 && len(s) <= 350
337		case kindTag:
338			return len(s) >= 1 && len(s) <= 80
339		default:
340			return len(s) >= 1 && len(s) <= 80
341		}
342	}
343	
344	func isValidPart(kind partKind, s string) bool {
345		if !isValidLen(kind, s) {
346			return false
347		}
348		for i := range s {
349			if i == 0 {
350				if !isAlphanumericOrUnderscore(s[i]) {
351					return false
352				}
353				continue
354			}
355			switch s[i] {
356			case '_', '-':
357			case '.':
358				if kind == kindNamespace {
359					return false
360				}
361			case ':':
362				if kind != kindHost && kind != kindDigest {
363					return false
364				}
365			default:
366				if !isAlphanumericOrUnderscore(s[i]) {
367					return false
368				}
369			}
370		}
371		return true
372	}
373	
374	func isAlphanumericOrUnderscore(c byte) bool {
375		return c >= 'A' && c <= 'Z' || c >= 'a' && c <= 'z' || c >= '0' && c <= '9' || c == '_'
376	}
377	
378	func cutLast(s, sep string) (before, after string, ok bool) {
379		i := strings.LastIndex(s, sep)
380		if i >= 0 {
381			return s[:i], s[i+len(sep):], true
382		}
383		return s, "", false
384	}
385	
386	// cutPromised cuts the last part of s at the last occurrence of sep. If sep is
387	// found, the part before and after sep are returned as-is unless empty, in
388	// which case they are returned as MissingPart, which will cause
389	// [Name.IsValid] to return false.
390	func cutPromised(s, sep string) (before, after string, ok bool) {
391		before, after, ok = cutLast(s, sep)
392		if !ok {
393			return before, after, false
394		}
395		return cmp.Or(before, MissingPart), cmp.Or(after, MissingPart), true
396	}
