3	// Package store provides a simple JSON file store for the desktop application
4	// to save and load data such as ollama server configuration, messages,
5	// login information and more.
6	package store
7	
8	import (
9		"encoding/json"
10		"fmt"
11		"log/slog"
12		"os"
13		"path/filepath"
14		"runtime"
15		"sync"
16		"time"
17	
18		"github.com/google/uuid"
19		"github.com/ollama/ollama/app/types/not"
20	)
21	
22	type File struct {
23		Filename string `json:"filename"`
24		Data     []byte `json:"data"`
25	}
26	
27	type User struct {
28		Name     string    `json:"name"`
29		Email    string    `json:"email"`
30		Plan     string    `json:"plan"`
31		CachedAt time.Time `json:"cachedAt"`
32	}
33	
34	type Message struct {
35		Role              string           `json:"role"`
36		Content           string           `json:"content"`
37		Thinking          string           `json:"thinking"`
38		Stream            bool             `json:"stream"`
39		Model             string           `json:"model,omitempty"`
40		Attachments       []File           `json:"attachments,omitempty"`
41		ToolCalls         []ToolCall       `json:"tool_calls,omitempty"`
42		ToolCall          *ToolCall        `json:"tool_call,omitempty"`
43		ToolName          string           `json:"tool_name,omitempty"`
44		ToolResult        *json.RawMessage `json:"tool_result,omitempty"`
45		CreatedAt         time.Time        `json:"created_at"`
46		UpdatedAt         time.Time        `json:"updated_at"`
47		ThinkingTimeStart *time.Time       `json:"thinkingTimeStart,omitempty" ts_type:"Date | undefined" ts_transform:"__VALUE__ && new Date(__VALUE__)"`
48		ThinkingTimeEnd   *time.Time       `json:"thinkingTimeEnd,omitempty" ts_type:"Date | undefined" ts_transform:"__VALUE__ && new Date(__VALUE__)"`
49	}
50	
51	// MessageOptions contains optional parameters for creating a Message
52	type MessageOptions struct {
53		Model             string
54		Attachments       []File
55		Stream            bool
56		Thinking          string
57		ToolCalls         []ToolCall
58		ToolCall          *ToolCall
59		ToolResult        *json.RawMessage
60		ThinkingTimeStart *time.Time
61		ThinkingTimeEnd   *time.Time
62	}
63	
64	// NewMessage creates a new Message with the given options
65	func NewMessage(role, content string, opts *MessageOptions) Message {
66		now := time.Now()
67		msg := Message{
68			Role:      role,
69			Content:   content,
70			CreatedAt: now,
71			UpdatedAt: now,
72		}
73	
74		if opts != nil {
75			msg.Model = opts.Model
76			msg.Attachments = opts.Attachments
77			msg.Stream = opts.Stream
78			msg.Thinking = opts.Thinking
79			msg.ToolCalls = opts.ToolCalls
80			msg.ToolCall = opts.ToolCall
81			msg.ToolResult = opts.ToolResult
82			msg.ThinkingTimeStart = opts.ThinkingTimeStart
83			msg.ThinkingTimeEnd = opts.ThinkingTimeEnd
84		}
85	
86		return msg
87	}
88	
89	type ToolCall struct {
90		Type     string       `json:"type"`
91		Function ToolFunction `json:"function"`
92	}
93	
94	type ToolFunction struct {
95		Name      string `json:"name"`
96		Arguments string `json:"arguments"`
97		Result    any    `json:"result,omitempty"`
98	}
99	
100	type Model struct {
101		Model      string     `json:"model"`                 // Model name
102		Digest     string     `json:"digest,omitempty"`      // Model digest from the registry
103		ModifiedAt *time.Time `json:"modified_at,omitempty"` // When the model was last modified locally
104	}
105	
106	type Chat struct {
107		ID           string          `json:"id"`
108		Messages     []Message       `json:"messages"`
109		Title        string          `json:"title"`
110		CreatedAt    time.Time       `json:"created_at"`
111		BrowserState json.RawMessage `json:"browser_state,omitempty" ts_type:"BrowserStateData"`
112	}
113	
114	// NewChat creates a new Chat with the ID, with CreatedAt timestamp initialized
115	func NewChat(id string) *Chat {
116		return &Chat{
117			ID:        id,
118			Messages:  []Message{},
119			CreatedAt: time.Now(),
120		}
121	}
122	
123	type Settings struct {
124		// Expose is a boolean that indicates if the ollama server should
125		// be exposed to the network
126		Expose bool
127	
128		// Browser is a boolean that indicates if the ollama server should
129		// be exposed to browser windows (e.g. CORS set to allow all origins)
130		Browser bool
131	
132		// Survey is a boolean that indicates if the user allows anonymous
133		// inference information to be shared with Ollama
134		Survey bool
135	
136		// Models is a string that contains the models to load on startup
137		Models string
138	
139		// TODO(parthsareen): temporary for experimentation
140		// Agent indicates if the app should use multi-turn tools to fulfill user requests
141		Agent bool
142	
143		// Tools indicates if the app should use single-turn tools to fulfill user requests
144		Tools bool
145	
146		// WorkingDir specifies the working directory for all agent operations
147		WorkingDir string
148	
149		// ContextLength specifies the context length for the ollama server (using OLLAMA_CONTEXT_LENGTH)
150		ContextLength int
151	
152		// TurboEnabled indicates if Ollama Turbo features are enabled
153		TurboEnabled bool
