215	func (s *Store) ensureDB() error {
216		// Fast path: check if db is already initialized
217		if s.db != nil {
218			return nil
219		}
220	
221		// Slow path: initialize database with lock
222		s.dbMu.Lock()
223		defer s.dbMu.Unlock()
224	
225		// Double-check after acquiring lock
226		if s.db != nil {
227			return nil
228		}
229	
230		dbPath := s.DBPath
231		if dbPath == "" {
232			dbPath = defaultDBPath
233		}
234	
235		// Ensure directory exists
236		if err := os.MkdirAll(filepath.Dir(dbPath), 0o755); err != nil {
237			return fmt.Errorf("create db directory: %w", err)
238		}
239	
240		database, err := newDatabase(dbPath)
241		if err != nil {
242			return fmt.Errorf("open database: %w", err)
243		}
244	
245		// Generate device ID if needed
246		id, err := database.getID()
247		if err != nil || id == "" {
248			// Generate new UUID for device
249			u, err := uuid.NewV7()
250			if err == nil {
251				database.setID(u.String())
252			}
253		}
254	
255		s.db = database
256	
257		// Check if we need to migrate from config.json
258		migrated, err := database.isConfigMigrated()
259		if err != nil || !migrated {
260			if err := s.migrateFromConfig(database); err != nil {
261				slog.Warn("failed to migrate from config.json", "error", err)
262			}
263		}
264	
265		// Run one-time migration from legacy airplane_mode behavior.
266		if err := s.migrateCloudSetting(database); err != nil {
267			return fmt.Errorf("migrate cloud setting: %w", err)
268		}
269	
270		return nil
271	}
