273	// migrateCloudSetting migrates legacy airplane_mode into server.json exactly once.
274	// After this, cloud state is sourced from server.json OR OLLAMA_NO_CLOUD.
275	func (s *Store) migrateCloudSetting(database *database) error {
276		migrated, err := database.isCloudSettingMigrated()
277		if err != nil {
278			return err
279		}
280		if migrated {
281			return nil
282		}
283	
284		airplaneMode, err := database.getAirplaneMode()
285		if err != nil {
286			return err
287		}
288	
289		if airplaneMode {
290			if err := setCloudEnabled(false); err != nil {
291				return fmt.Errorf("migrate airplane_mode to cloud disabled: %w", err)
292			}
293		}
294	
295		if err := database.setCloudSettingMigrated(true); err != nil {
296			return err
297		}
298	
299		return nil
300	}
301	
302	// migrateFromConfig attempts to migrate ID and FirstTimeRun from config.json
303	func (s *Store) migrateFromConfig(database *database) error {
304		configPath := legacyConfigPath
305	
306		// Check if config.json exists
307		if _, err := os.Stat(configPath); os.IsNotExist(err) {
308			// No config to migrate, mark as migrated
309			return database.setConfigMigrated(true)
310		}
311	
312		// Read the config file
313		b, err := os.ReadFile(configPath)
314		if err != nil {
315			return fmt.Errorf("read legacy config: %w", err)
316		}
317	
318		var legacy legacyData
319		if err := json.Unmarshal(b, &legacy); err != nil {
320			// If we can't parse it, just mark as migrated and move on
321			slog.Warn("failed to parse legacy config.json", "error", err)
322			return database.setConfigMigrated(true)
323		}
324	
325		// Migrate the ID if present
326		if legacy.ID != "" {
327			if err := database.setID(legacy.ID); err != nil {
328				return fmt.Errorf("migrate device ID: %w", err)
329			}
330			slog.Info("migrated device ID from config.json")
331		}
332	
333		hasCompleted := legacy.FirstTimeRun // If old FirstTimeRun is true, it means first run was completed
334		if err := database.setHasCompletedFirstRun(hasCompleted); err != nil {
335			return fmt.Errorf("migrate first time run: %w", err)
336		}
337		slog.Info("migrated first run status from config.json", "hasCompleted", hasCompleted)
338	
339		// Mark as migrated
340		if err := database.setConfigMigrated(true); err != nil {
341			return fmt.Errorf("mark config as migrated: %w", err)
342		}
343	
344		slog.Info("successfully migrated settings from config.json")
345		return nil
346	}
