16	type Manifest struct {
17		SchemaVersion int     `json:"schemaVersion"`
18		MediaType     string  `json:"mediaType"`
19		Config        Layer   `json:"config"`
20		Layers        []Layer `json:"layers"`
21	
22		filepath string
23		fi       os.FileInfo
24		digest   string
25	}
26	
27	func (m *Manifest) Size() (size int64) {
28		for _, layer := range append(m.Layers, m.Config) {
29			size += layer.Size
30		}
31	
32		return
33	}
34	
35	func (m *Manifest) Digest() string {
36		return m.digest
37	}
38	
39	func (m *Manifest) FileInfo() os.FileInfo {
40		return m.fi
41	}
42	
43	// ReadConfigJSON reads and unmarshals a config layer as JSON.
44	func (m *Manifest) ReadConfigJSON(configPath string, v any) error {
45		for _, layer := range m.Layers {
46			if layer.MediaType == "application/vnd.ollama.image.json" && layer.Name == configPath {
47				blobPath, err := BlobsPath(layer.Digest)
48				if err != nil {
49					return err
50				}
51				data, err := os.ReadFile(blobPath)
52				if err != nil {
53					return err
54				}
55				return json.Unmarshal(data, v)
56			}
57		}
58		return fmt.Errorf("config %q not found in manifest", configPath)
59	}
60	
61	func (m *Manifest) Remove() error {
62		if err := os.Remove(m.filepath); err != nil {
63			return err
64		}
65	
66		manifests, err := Path()
67		if err != nil {
68			return err
69		}
70	
71		return PruneDirectory(manifests)
72	}
73	
74	func (m *Manifest) RemoveLayers() error {
75		ms, err := Manifests(true)
76		if err != nil {
77			return err
78		}
79	
80		// Build set of digests still in use by other manifests
81		inUse := make(map[string]struct{})
82		for _, other := range ms {
83			for _, layer := range append(other.Layers, other.Config) {
84				if layer.Digest != "" {
85					inUse[layer.Digest] = struct{}{}
86				}
87			}
88		}
89	
90		// Remove layers not used by any other manifest
91		for _, layer := range append(m.Layers, m.Config) {
92			if layer.Digest == "" {
93				continue
94			}
95			if _, used := inUse[layer.Digest]; used {
96				continue
97			}
98			blob, err := BlobsPath(layer.Digest)
99			if err != nil {
100				return err
101			}
102			if err := os.Remove(blob); os.IsNotExist(err) {
103				slog.Debug("layer does not exist", "digest", layer.Digest)
104			} else if err != nil {
105				return err
106			}
107		}
108	
109		return nil
110	}
111	
112	func ParseNamedManifest(n model.Name) (*Manifest, error) {
113		if !n.IsFullyQualified() {
114			return nil, model.Unqualified(n)
115		}
116	
117		manifests, err := Path()
118		if err != nil {
119			return nil, err
120		}
121	
122		p := filepath.Join(manifests, n.Filepath())
123	
124		var m Manifest
125		f, err := os.Open(p)
126		if err != nil {
127			return nil, err
128		}
129		defer f.Close()
130	
131		fi, err := f.Stat()
132		if err != nil {
133			return nil, err
134		}
135	
136		sha256sum := sha256.New()
137		if err := json.NewDecoder(io.TeeReader(f, sha256sum)).Decode(&m); err != nil {
138			return nil, err
139		}
140	
141		m.filepath = p
142		m.fi = fi
143		m.digest = hex.EncodeToString(sha256sum.Sum(nil))
144	
145		return &m, nil
146	}
147	
148	func WriteManifest(name model.Name, config Layer, layers []Layer) error {
149		manifests, err := Path()
150		if err != nil {
151			return err
152		}
153	
154		p := filepath.Join(manifests, name.Filepath())
155		if err := os.MkdirAll(filepath.Dir(p), 0o755); err != nil {
156			return err
157		}
158	
159		f, err := os.Create(p)
160		if err != nil {
161			return err
162		}
163		defer f.Close()
164	
165		m := Manifest{
166			SchemaVersion: 2,
167			MediaType:     "application/vnd.docker.distribution.manifest.v2+json",
168			Config:        config,
169			Layers:        layers,
170		}
171	
172		return json.NewEncoder(f).Encode(m)
173	}
174	
175	func Manifests(continueOnError bool) (map[model.Name]*Manifest, error) {
176		manifests, err := Path()
177		if err != nil {
178			return nil, err
179		}
180	
181		// TODO(mxyng): use something less brittle
182		matches, err := filepath.Glob(filepath.Join(manifests, "*", "*", "*", "*"))
183		if err != nil {
184			return nil, err
185		}
186	
187		ms := make(map[model.Name]*Manifest)
188		for _, match := range matches {
189			fi, err := os.Stat(match)
190			if err != nil {
191				return nil, err
192			}
193	
194			if !fi.IsDir() {
195				rel, err := filepath.Rel(manifests, match)
196				if err != nil {
197					if !continueOnError {
198						return nil, fmt.Errorf("%s %w", match, err)
199					}
200					slog.Warn("bad filepath", "path", match, "error", err)
201					continue
202				}
203	
204				n := model.ParseNameFromFilepath(rel)
205				if !n.IsValid() {
206					if !continueOnError {
207						return nil, fmt.Errorf("%s %w", rel, err)
208					}
209					slog.Warn("bad manifest name", "path", rel)
210					continue
211				}
212	
213				m, err := ParseNamedManifest(n)
214				if err != nil {
215					if !continueOnError {
216						return nil, fmt.Errorf("%s %w", n, err)
217					}
218					slog.Warn("bad manifest", "name", n, "error", err)
219					continue
220				}
221	
222				ms[n] = m
223			}
224		}
225	
226		return ms, nil
227	}
