168	// CheckCapabilities checks if the model has the specified capabilities returning an error describing
169	// any missing or unknown capabilities
170	func (m *Model) CheckCapabilities(want ...model.Capability) error {
171		available := m.Capabilities()
172		var errs []error
173	
174		// Map capabilities to their corresponding error
175		capToErr := map[model.Capability]error{
176			model.CapabilityCompletion: errCapabilityCompletion,
177			model.CapabilityTools:      errCapabilityTools,
178			model.CapabilityInsert:     errCapabilityInsert,
179			model.CapabilityVision:     errCapabilityVision,
180			model.CapabilityAudio:      errCapabilityAudio,
181			model.CapabilityEmbedding:  errCapabilityEmbedding,
182			model.CapabilityThinking:   errCapabilityThinking,
183			model.CapabilityImage:      errCapabilityImage,
184		}
185	
186		for _, cap := range want {
187			err, ok := capToErr[cap]
188			if !ok {
189				slog.Error("unknown capability", "capability", cap)
190				return fmt.Errorf("unknown capability: %s", cap)
191			}
192	
193			if !slices.Contains(available, cap) {
194				errs = append(errs, err)
195			}
196		}
197	
198		var err error
199		if len(errs) > 0 {
200			err = fmt.Errorf("%w %w", errCapabilities, errors.Join(errs...))
201		}
202	
203		if slices.Contains(errs, errCapabilityThinking) {
204			if m.Config.ModelFamily == "qwen3" || model.ParseName(m.Name).Model == "deepseek-r1" {
205				// append a message to the existing error
206				return fmt.Errorf("%w. Pull the model again to get the latest version with full thinking support", err)
207			}
208		}
209	
210		return err
211	}
