436	func deleteUnusedLayers(deleteMap map[string]struct{}) error {
437		// Ignore corrupt manifests to avoid blocking deletion of layers that are freshly orphaned
438		manifests, err := manifest.Manifests(true)
439		if err != nil {
440			return err
441		}
442	
443		for _, manifest := range manifests {
444			for _, layer := range manifest.Layers {
445				delete(deleteMap, layer.Digest)
446			}
447	
448			delete(deleteMap, manifest.Config.Digest)
449		}
450	
451		// only delete the files which are still in the deleteMap
452		for k := range deleteMap {
453			fp, err := manifest.BlobsPath(k)
454			if err != nil {
455				slog.Info(fmt.Sprintf("couldn't get file path for '%s': %v", k, err))
456				continue
457			}
458			if err := os.Remove(fp); err != nil {
459				slog.Info(fmt.Sprintf("couldn't remove file '%s': %v", fp, err))
460				continue
461			}
462		}
463	
464		return nil
465	}
