702	// pullWithTransfer uses the simplified x/transfer package for downloading blobs.
703	func pullWithTransfer(ctx context.Context, n model.Name, layers []manifest.Layer, manifestData []byte, regOpts *registryOptions, fn func(api.ProgressResponse)) error {
704		blobs := make([]transfer.Blob, len(layers))
705		for i, layer := range layers {
706			blobs[i] = transfer.Blob{
707				Digest: layer.Digest,
708				Size:   layer.Size,
709			}
710		}
711	
712		destDir, err := manifest.BlobsPath("")
713		if err != nil {
714			return err
715		}
716	
717		base := n.BaseURL()
718		if base.Scheme != "http" && regOpts != nil && regOpts.Insecure {
719			base.Scheme = "http"
720		}
721		baseURL := base.String()
722	
723		var totalSize int64
724		for _, blob := range blobs {
725			totalSize += blob.Size
726		}
727	
728		progress := func(completed, total int64) {
729			fn(api.ProgressResponse{
730				Status:    "pulling model",
731				Digest:    "sha256:model",
732				Total:     total,
733				Completed: completed,
734			})
735		}
736	
737		getToken := func(ctx context.Context, challenge transfer.AuthChallenge) (string, error) {
738			return getAuthorizationToken(ctx, registryChallenge{
739				Realm:   challenge.Realm,
740				Service: challenge.Service,
741				Scope:   challenge.Scope,
742			}, base.Host)
743		}
744	
745		if err := transfer.Download(ctx, transfer.DownloadOptions{
746			Blobs:      blobs,
747			BaseURL:    baseURL,
748			DestDir:    destDir,
749			Repository: n.DisplayNamespaceModel(),
750			Progress:   progress,
751			Token:      regOpts.Token,
752			GetToken:   getToken,
753			Logger:     slog.Default(),
754		}); err != nil {
755			return err
756		}
757	
758		// Write manifest
759		fn(api.ProgressResponse{Status: "writing manifest"})
760	
761		fp, err := manifest.PathForName(n)
762		if err != nil {
763			return err
764		}
765		if err := os.MkdirAll(filepath.Dir(fp), 0o755); err != nil {
766			return err
767		}
768	
769		if err := os.WriteFile(fp, manifestData, 0o644); err != nil {
770			return err
771		}
772	
773		slog.Debug("manifest written", "path", fp, "sha256", fmt.Sprintf("%x", sha256.Sum256(manifestData)), "size", len(manifestData))
774		return nil
775	}
