80		}
81	
82		fi, err := os.Stat(blob)
83		if err != nil {
84			return Layer{}, err
85		}
86	
87		return Layer{
88			MediaType: mediatype,
89			Digest:    digest,
90			Size:      fi.Size(),
91			From:      from,
92			Status:    fmt.Sprintf("using existing layer %s", digest),
93		}, nil
