145	// Resolve resolves a name to a digest. The name is expected to
146	// be in either of the following forms:
147	//
148	//	@<digest>
149	//	<name>@<digest>
150	//	<name>
151	//
152	// If a digest is provided, it is returned as is and nothing else happens.
153	//
154	// If a name is provided for a manifest that exists in the cache, the digest
155	// of the manifest is returned. If there is no manifest in the cache, it
156	// returns [fs.ErrNotExist].
157	//
158	// To cover the case where a manifest may change without the cache knowing
159	// (e.g. it was reformatted or modified by hand), the manifest data read and
160	// hashed is passed to a PutBytes call to ensure that the manifest is in the
161	// blob store. This is done to ensure that future calls to [Get] succeed in
162	// these cases.
163	func (c *DiskCache) Resolve(name string) (Digest, error) {
164		name, digest := splitNameDigest(name)
165		if digest != "" {
166			return ParseDigest(digest)
167		}
168	
169		// We want to address manifests files by digest using Get. That requires
170		// them to be blobs. This cannot be directly accomplished by looking in
171		// the blob store because manifests can change without Ollama knowing
172		// (e.g. a user modifies a manifests by hand then pushes it to update
173		// their model). We also need to support the blob caches inherited from
174		// older versions of Ollama, which do not store manifests in the blob
175		// store, so for these cases, we need to handle adding the manifests to
176		// the blob store, just in time.
177		//
178		// So now we read the manifests file, hash it, and copy it to the blob
179		// store if it's not already there.
180		//
181		// This should be cheap because manifests are small, and accessed
182		// infrequently.
183		file, err := c.manifestPath(name)
184		if err != nil {
185			return Digest{}, err
186		}
187	
188		data, d, err := readAndSum(file, 1<<20)
189		if err != nil {
190			return Digest{}, err
191		}
192	
193		// Ideally we'd read the "manifest" file as a manifest to the blob file,
194		// but we are not changing this yet, so copy the manifest to the blob
195		// store so it can be addressed by digest subsequent calls to Get.
196		if err := PutBytes(c, d, data); err != nil {
197			return Digest{}, err
198		}
199		return d, nil
200	}
