202	// Put writes a new blob to the cache, identified by its digest. The operation
203	// reads content from r, which must precisely match both the specified size and
204	// digest.
205	//
206	// Concurrent write safety is achieved through file locking. The implementation
207	// guarantees write integrity by enforcing size limits and content validation
208	// before allowing the file to reach its final state.
209	func (c *DiskCache) Put(d Digest, r io.Reader, size int64) error {
210		return c.copyNamedFile(c.GetFile(d), r, d, size)
211	}
