213	// Import imports a blob from the provided reader into the cache. It reads the
214	// entire content of the reader, calculates its digest, and stores it in the
215	// cache.
216	//
217	// Import should be considered unsafe for use with untrusted data, such as data
218	// read from a network. The caller is responsible for ensuring the integrity of
219	// the data being imported.
220	func (c *DiskCache) Import(r io.Reader, size int64) (Digest, error) {
221		// users that want to change the temp dir can set TEMPDIR.
222		f, err := os.CreateTemp("", "blob-")
223		if err != nil {
224			return Digest{}, err
225		}
226		defer os.Remove(f.Name())
227	
228		// Copy the blob to a temporary file.
229		h := sha256.New()
230		r = io.TeeReader(r, h)
231		n, err := io.Copy(f, r)
232		if err != nil {
233			return Digest{}, err
234		}
235		if n != size {
236			return Digest{}, fmt.Errorf("blob: expected %d bytes, got %d", size, n)
237		}
238	
239		// Check the digest.
240		var d Digest
241		h.Sum(d.sum[:0])
242		if err := f.Close(); err != nil {
243			return Digest{}, err
244		}
245		name := c.GetFile(d)
246		// Rename the temporary file to the final file.
247		if err := os.Rename(f.Name(), name); err != nil {
248			return Digest{}, err
249		}
250		os.Chtimes(name, c.now(), c.now()) // mainly for tests
251		return d, nil
252	}
