254	// Get retrieves a blob from the cache using the provided digest. The operation
255	// fails if the digest is malformed or if any errors occur during blob
256	// retrieval.
257	func (c *DiskCache) Get(d Digest) (Entry, error) {
258		name := c.GetFile(d)
259		info, err := os.Stat(name)
260		if err != nil {
261			return Entry{}, err
262		}
263		if info.Size() == 0 {
264			return Entry{}, fs.ErrNotExist
265		}
266		return Entry{
267			Digest: d,
268			Size:   info.Size(),
269			Time:   info.ModTime(),
270		}, nil
271	}
