273	// Link creates a symbolic reference in the cache that maps the provided name
274	// to a blob identified by its digest, making it retrievable by name using
275	// [Resolve].
276	//
277	// It returns an error if either the name or digest is invalid, or if link
278	// creation encounters any issues.
279	func (c *DiskCache) Link(name string, d Digest) error {
280		manifest, err := c.manifestPath(name)
281		if err != nil {
282			return err
283		}
284		f, err := os.OpenFile(c.GetFile(d), os.O_RDONLY, 0)
285		if err != nil {
286			return err
287		}
288		defer f.Close()
289	
290		// TODO(bmizerany): test this happens only if the blob was found to
291		// avoid leaving debris
292		if err := os.MkdirAll(filepath.Dir(manifest), 0o777); err != nil {
293			return err
294		}
295	
296		info, err := f.Stat()
297		if err != nil {
298			return err
299		}
300	
301		// Copy manifest to cache directory.
302		return c.copyNamedFile(manifest, f, d, info.Size())
303	}
