305	// Unlink unlinks the manifest by name from the cache. If the name is not
306	// found. If a manifest is removed ok will be true, otherwise false. If an
307	// error occurs, it returns ok false, and the error.
308	func (c *DiskCache) Unlink(name string) (ok bool, _ error) {
309		manifest, err := c.manifestPath(name)
310		if err != nil {
311			return false, err
312		}
313		err = os.Remove(manifest)
314		if errors.Is(err, fs.ErrNotExist) {
315			return false, nil
316		}
317		return true, err
318	}
