330	// Links returns a sequence of link names. The sequence is in lexical order.
331	// Names are converted from their relative path form to their name form but are
332	// not guaranteed to be valid. Callers should validate the names before using.
333	func (c *DiskCache) Links() iter.Seq2[string, error] {
334		return func(yield func(string, error) bool) {
335			for path, err := range c.links() {
336				if err != nil {
337					yield("", err)
338					return
339				}
340				if !yield(pathToName(path), nil) {
341					return
342				}
343			}
344		}
345	}
