347	// pathToName converts a path to a name. It is the inverse of nameToPath. The
348	// path is assumed to be in filepath.ToSlash format.
349	func pathToName(s string) string {
350		s = strings.TrimPrefix(s, "manifests/")
351		rr := []rune(s)
352		for i := len(rr) - 1; i > 0; i-- {
353			if rr[i] == '/' {
354				rr[i] = ':'
355				return string(rr)
356			}
357		}
358		return s
359	}
