361	// manifestPath finds the first manifest file on disk that matches the given
362	// name using a case-insensitive comparison. If no manifest file is found, it
363	// returns the path where the manifest file would be if it existed.
364	//
365	// If two manifest files exists on disk that match the given name using a
366	// case-insensitive comparison, the one that sorts first, lexically, is
367	// returned.
368	func (c *DiskCache) manifestPath(name string) (string, error) {
369		np, err := nameToPath(name)
370		if err != nil {
371			return "", err
372		}
373	
374		maybe := filepath.Join("manifests", np)
375		for l, err := range c.links() {
376			if err != nil {
377				return "", err
378			}
379			if strings.EqualFold(maybe, l) {
380				return filepath.Join(c.dir, l), nil
381			}
382		}
383		return filepath.Join(c.dir, maybe), nil
384	}
