386	// links returns a sequence of links in the cache in lexical order.
387	func (c *DiskCache) links() iter.Seq2[string, error] {
388		// TODO(bmizerany): reuse empty dirnames if exist
389		return func(yield func(string, error) bool) {
390			fsys := os.DirFS(c.dir)
391			manifests, err := fs.Glob(fsys, "manifests/*/*/*/*")
392			if err != nil {
393				yield("", err)
394				return
395			}
396			for _, manifest := range manifests {
397				if !yield(manifest, nil) {
398					return
399				}
400			}
401		}
402	}
