404	type checkWriter struct {
405		size int64
406		d    Digest
407		f    *os.File
408		h    hash.Hash
409	
410		w   io.Writer // underlying writer; set by creator
411		n   int64
412		err error
413	
414		testHookBeforeFinalWrite func(*os.File)
415	}
416	
417	func (w *checkWriter) seterr(err error) error {
418		if w.err == nil {
419			w.err = err
420		}
421		return err
422	}
423	
424	// Write writes p to the underlying hash and writer. The last write to the
425	// underlying writer is guaranteed to be the last byte of p as verified by the
426	// hash.
427	func (w *checkWriter) Write(p []byte) (int, error) {
428		if w.err != nil {
429			return 0, w.err
430		}
431	
432		_, err := w.h.Write(p)
433		if err != nil {
434			return 0, w.seterr(err)
435		}
436		nextSize := w.n + int64(len(p))
437		if nextSize == w.size {
438			// last write. check hash.
439			sum := w.h.Sum(nil)
440			if !bytes.Equal(sum, w.d.sum[:]) {
441				return 0, w.seterr(fmt.Errorf("file content changed underfoot"))
442			}
443			if w.testHookBeforeFinalWrite != nil {
444				w.testHookBeforeFinalWrite(w.f)
445			}
446		}
447		if nextSize > w.size {
448			return 0, w.seterr(fmt.Errorf("content exceeds expected size: %d > %d", nextSize, w.size))
449		}
450		n, err := w.w.Write(p)
451		w.n += int64(n)
452		return n, w.seterr(err)
453	}
