455	// copyNamedFile copies file into name, expecting it to have the given Digest
456	// and size, if that file is not present already.
457	func (c *DiskCache) copyNamedFile(name string, file io.Reader, out Digest, size int64) error {
458		info, err := os.Stat(name)
459		if err == nil && info.Size() == size {
460			// File already exists with correct size. This is good enough.
461			// We can skip expensive hash checks.
462			//
463			// TODO: Do the hash check, but give caller a way to skip it.
464			return nil
465		}
466	
467		// Copy file to cache directory.
468		mode := os.O_RDWR | os.O_CREATE
469		if err == nil && info.Size() > size { // shouldn't happen but fix in case
470			mode |= os.O_TRUNC
471		}
472		f, err := os.OpenFile(name, mode, 0o666)
473		if err != nil {
474			return err
475		}
476		defer f.Close()
477		if size == 0 {
478			// File now exists with correct size.
479			// Only one possible zero-length file, so contents are OK too.
480			// Early return here makes sure there's a "last byte" for code below.
481			return nil
482		}
483	
484		// From here on, if any of the I/O writing the file fails,
485		// we make a best-effort attempt to truncate the file f
486		// before returning, to avoid leaving bad bytes in the file.
487	
488		// Copy file to f, but also into h to double-check hash.
489		cw := &checkWriter{
490			d:    out,
491			size: size,
492			h:    sha256.New(),
493			f:    f,
494			w:    f,
495	
496			testHookBeforeFinalWrite: c.testHookBeforeFinalWrite,
497		}
498		n, err := io.Copy(cw, file)
499		if err != nil {
500			f.Truncate(0)
501			return err
502		}
503		if n < size {
504			f.Truncate(0)
505			return io.ErrUnexpectedEOF
506		}
507	
508		if err := f.Close(); err != nil {
509			// Data might not have been written,
510			// but file may look like it is the right size.
511			// To be extra careful, remove cached file.
512			os.Remove(name)
513			return err
514		}
515		os.Chtimes(name, c.now(), c.now()) // mainly for tests
516	
517		return nil
518	}
